/**
 * Regenerate the committed Plato clash-math outputs (Rust + TypeScript) from
 * the single .plato source in tools/plato/.
 *
 * Consumers NEVER need this script or a .NET SDK: the generated files under
 * rust/clash/src/generated/plato.rs and packages/clash/src/math/generated/
 * plato.g.ts are committed and are the source of truth for every build. This
 * script only runs when the .plato source changes; a CI freshness gate
 * (--check) proves the committed outputs are still in sync.
 *
 * Pipeline (mirrors the committed-wasm-types pattern, scripts/build-wasm.sh):
 *   1. clone plato + ara3d-sdk at pinned SHAs (skipped when already present)
 *   2. dotnet build the Plato.CLI (requires the .NET 9 SDK)
 *   3. run the CLI for --rust and --typescript over tools/plato/
 *   4. verify each raw output exists and exceeds MIN_BYTES -- the CLI exits 0
 *      even when parsing/compilation fails, so the size check is the ONLY
 *      signal that generation actually happened (repo-critical trap)
 *   5. TS only: run the scalar codemod (tools/plato/scalar-codemod.mjs)
 *   6. strip the nondeterministic "// Created on <ts>" line and prepend the
 *      canonical DO-NOT-EDIT header
 *   7. write the finalized outputs to their committed locations
 *
 * Usage:
 *   node scripts/generate-plato-clash.mjs            # regenerate + write committed outputs
 *   node scripts/generate-plato-clash.mjs --check    # CI gate: fail if committed outputs are stale
 *
 * Env overrides (CI leaves them unset; local reuse of an existing checkout/SDK
 * avoids re-downloading):
 *   PLATO_WORK_DIR   work/cache root holding the ara3d-sdk + plato checkouts
 *                    (default: <repo>/node_modules/.cache/ifc-lite-plato)
 *   PLATO_SUBDIR     subdir under the work root that holds the plato checkout.
 *                    It exists so the Plato.CLI csproj's ..\..\..\ara3d-sdk
 *                    reference resolves to <work>/ara3d-sdk (default: src)
 *   PLATO_DOTNET     dotnet executable (default: dotnet on PATH)
 *   PLATO_RUST_OUT   final Rust output path (default: committed location)
 *   PLATO_TS_OUT     final TypeScript output path (default: committed location)
 */

import { execFileSync } from 'node:child_process';
import {
  existsSync,
  mkdirSync,
  mkdtempSync,
  readFileSync,
  rmSync,
  statSync,
  writeFileSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const rootDir = resolve(__dirname, '..');

// ---- Pins (see tools/plato/README.md) -------------------------------------
const PLATO_REMOTE = 'https://github.com/cdiggins/plato';
const PLATO_SHA = '18538a4c1ddb5f7bea5bd135b5712b7625c22845';
const PARAKEET_SHA = '1e385d19e1eba592595df1cc46ae948f0d419bfc';
const ARA3D_REMOTE = 'https://github.com/ara3d/ara3d-sdk';
const ARA3D_SHA = '030c9350ef56f883e96bdeacf0f8a467ec7b21df';

// ---- Paths ----------------------------------------------------------------
const platoSrcDir = join(rootDir, 'tools', 'plato');
const codemod = join(platoSrcDir, 'scalar-codemod.mjs');
const rustOut = process.env.PLATO_RUST_OUT || join(rootDir, 'rust/clash/src/generated/plato.rs');
const tsOut = process.env.PLATO_TS_OUT || join(rootDir, 'packages/clash/src/math/generated/plato.g.ts');

const workDir = process.env.PLATO_WORK_DIR || join(rootDir, 'node_modules/.cache/ifc-lite-plato');
const subdir = process.env.PLATO_SUBDIR || 'src';
const dotnet = process.env.PLATO_DOTNET || 'dotnet';

const ara3dDir = join(workDir, 'ara3d-sdk');
const platoDir = join(workDir, subdir, 'plato');

// The exact header block every generated output must carry (MPL notice per
// AGENTS.md, then the DO-NOT-EDIT line). The upstream CLI emits
// "// Autogenerated file: DO NOT EDIT" + "// Created on <timestamp>"; that
// nondeterministic block is stripped and replaced with this one.
const HEADER_LINES = [
  '// This Source Code Form is subject to the terms of the Mozilla Public',
  '// License, v. 2.0. If a copy of the MPL was not distributed with this',
  '// file, You can obtain one at https://mozilla.org/MPL/2.0/.',
  '// Autogenerated from tools/plato/clash_math.plato - DO NOT EDIT (see tools/plato/README.md)',
];
const HEADER = HEADER_LINES.join('\n');
const UPSTREAM_HEADER = '// Autogenerated file: DO NOT EDIT';
const KNOWN_HEADER_LINES = new Set([UPSTREAM_HEADER, ...HEADER_LINES]);
const MIN_BYTES = 5000;

function log(msg) {
  console.log(msg);
}

// Every mkdtempSync dir is registered here and removed on exit, so repeated
// regenerate/--check runs do not leak temp directories.
const tempDirs = [];
function tempDir(prefix) {
  const dir = mkdtempSync(join(tmpdir(), prefix));
  tempDirs.push(dir);
  return dir;
}
process.on('exit', () => {
  for (const dir of tempDirs) {
    try {
      rmSync(dir, { recursive: true, force: true });
    } catch {
      /* best effort */
    }
  }
});

function run(cmd, args, opts = {}) {
  execFileSync(cmd, args, { stdio: 'inherit', ...opts });
}

// Clone `remote` into `dir` and check out `sha`. `sentinel` is a file that must
// exist for an already-present checkout to count as reusable -- this lets a
// pre-extracted (non-git) tree be reused via PLATO_WORK_DIR without a network
// round-trip. A full clone + checkout is used (not a shallow SHA fetch) so the
// pin resolves against any commit regardless of server fetch-by-SHA policy.
function ensureCheckout(dir, remote, sha, sentinel) {
  if (existsSync(join(dir, sentinel))) {
    // Reuse is only trusted at the pinned SHA. A non-git tree (pre-extracted
    // via PLATO_WORK_DIR) cannot be verified, so it is reused with a warning.
    if (existsSync(join(dir, '.git'))) {
      const head = execFileSync('git', ['-C', dir, 'rev-parse', 'HEAD'], {
        encoding: 'utf8',
      }).trim();
      if (head !== sha) {
        log(`   cached checkout at ${dir} is at ${head.slice(0, 12)}, re-pinning to ${sha.slice(0, 12)}`);
        run('git', ['-C', dir, 'fetch', 'origin', sha]);
        run('git', ['-C', dir, 'checkout', '--detach', sha]);
        return;
      }
      log(`   reusing existing checkout at ${dir} (verified at pin)`);
      return;
    }
    log(`   reusing pre-extracted (non-git) tree at ${dir} -- pin not verifiable`);
    return;
  }
  log(`   cloning ${remote} -> ${dir}`);
  mkdirSync(dirname(dir), { recursive: true });
  run('git', ['clone', remote, dir]);
  run('git', ['-C', dir, 'checkout', '--detach', sha]);
}

function buildCli() {
  log('Preparing Plato toolchain');
  // ara3d-sdk must sit at <work>/ara3d-sdk: the Plato.CLI csproj references it
  // via ..\..\..\ara3d-sdk from <work>/<subdir>/plato/Plato.CLI/.
  ensureCheckout(ara3dDir, ARA3D_REMOTE, ARA3D_SHA, 'src/Ara3D.Utils/Ara3D.Utils.csproj');
  ensureCheckout(platoDir, PLATO_REMOTE, PLATO_SHA, 'Plato.CLI/Plato.CLI.csproj');

  // Pin the parakeet submodule. When we did the clone above the submodule tree
  // is empty; when reusing an existing checkout it is already populated. Init
  // it and force the pinned SHA either way (no-op when already correct). Only
  // meaningful when plato is a real git checkout (a pre-extracted tree already
  // carries parakeet).
  if (existsSync(join(platoDir, '.git'))) {
    run('git', ['-C', platoDir, 'submodule', 'update', '--init', '--recursive']);
    try {
      run('git', ['-C', join(platoDir, 'parakeet'), 'checkout', '--detach', PARAKEET_SHA]);
    } catch {
      // A pre-extracted parakeet tree may not be a git repo; the pinned plato
      // checkout already records the right gitlink, so tolerate this.
      log('   (parakeet not a git checkout; relying on recorded submodule pin)');
    }
  }

  log(`Building Plato.CLI (${dotnet})`);
  run(dotnet, ['build', join(platoDir, 'Plato.CLI'), '-c', 'Release', '--nologo'], { cwd: platoDir });

  const dll = join(platoDir, 'Plato.CLI/bin/Release/net9.0/Plato.CLI.dll');
  if (!existsSync(dll)) {
    throw new Error(`Plato.CLI build did not produce ${dll}`);
  }
  return dll;
}

// The CLI compiles every *.plato in its input folder, but Directory.GetFiles
// enumeration order is filesystem-dependent (APFS and ext4 disagree), and
// declaration order follows file order into the generated output. Concatenate
// the sources in a FIXED order into a single temp input file so generation is
// byte-identical on every platform.
const PLATO_SOURCES = ['clash_math.plato', 'scaffold.plato'];
let canonicalDir = null;
function canonicalInputDir() {
  if (canonicalDir) return canonicalDir;
  canonicalDir = tempDir('plato-src-');
  const merged = PLATO_SOURCES.map((f) =>
    readFileSync(join(platoSrcDir, f), 'utf8').replace(/\s*$/, '\n'),
  ).join('\n');
  writeFileSync(join(canonicalDir, 'clash_math.plato'), merged);
  return canonicalDir;
}

// Run the CLI for one backend and return the path to the single produced file.
// The CLI ALWAYS exits 0 (even on a parse/compile failure), so success is
// judged solely by the output file existing and clearing MIN_BYTES.
function runBackend(dll, flag, filename) {
  const outDir = tempDir(`plato-${flag.replace(/^-+/, '')}-`);
  run(dotnet, [dll, canonicalInputDir(), outDir, flag]);
  const file = join(outDir, filename);
  if (!existsSync(file)) {
    throw new Error(
      `Plato.CLI ${flag} produced no ${filename} in ${outDir}. The CLI exits 0 even on ` +
        `failure -- check the log above for a parse/compile error in tools/plato/*.plato.`,
    );
  }
  const size = statSync(file).size;
  if (size < MIN_BYTES) {
    throw new Error(
      `Plato.CLI ${flag} output ${file} is only ${size} bytes (< ${MIN_BYTES}). The CLI exits 0 ` +
        `even on failure; this almost always means generation silently produced a stub.`,
    );
  }
  return file;
}

// Strip the leading contiguous block of upstream-autogenerated / "// Created on"
// lines and prepend the canonical header. Idempotent: re-running on already
// finalized text (canonical header already present) reproduces the same bytes.
function finalizeHeader(text) {
  const lines = text.split('\n');
  let i = 0;
  while (i < lines.length) {
    const l = lines[i];
    if (KNOWN_HEADER_LINES.has(l) || /^\/\/ Created on /.test(l)) {
      i += 1;
    } else {
      break;
    }
  }
  return [HEADER, ...lines.slice(i)].join('\n');
}

function writeOut(dest, text) {
  mkdirSync(dirname(dest), { recursive: true });
  writeFileSync(dest, text);
}

// Produce both finalized outputs at `targets.rust` / `targets.ts`.
function generate(dll, targets) {
  log('Generating Rust');
  const rawRust = readFileSync(runBackend(dll, '--rust', 'plato.rs'), 'utf8');
  writeOut(targets.rust, finalizeHeader(rawRust));
  log(`   wrote ${targets.rust}`);

  log('Generating TypeScript');
  const rawTsFile = runBackend(dll, '--typescript', 'plato.g.ts');
  if (!existsSync(codemod)) {
    throw new Error(`${codemod} not found; the committed TS is codemod output, refusing to emit raw CLI TypeScript`);
  }
  // Contract: node tools/plato/scalar-codemod.mjs <rawInput> <output>. Phase 1
  // erases scalar dispatch to native operators, phase 2 (flatten-codemod.mjs)
  // emits the tuple-native flat kernels; both run BEFORE header finalization.
  const codemodOut = join(dirname(rawTsFile), 'plato.codemod.g.ts');
  run(process.execPath, [codemod, rawTsFile, codemodOut]);
  if (!existsSync(codemodOut) || statSync(codemodOut).size < MIN_BYTES) {
    throw new Error(`scalar-codemod.mjs produced no usable output at ${codemodOut}`);
  }
  writeOut(targets.ts, finalizeHeader(readFileSync(codemodOut, 'utf8')));
  log(`   wrote ${targets.ts}`);
}

function checkMode(dll) {
  log('--check: regenerating to a temp location and diffing against committed outputs');
  const tmp = tempDir('plato-check-');
  const targets = { rust: join(tmp, 'plato.rs'), ts: join(tmp, 'plato.g.ts') };
  generate(dll, targets);

  const drift = [];
  for (const [committed, fresh] of [
    [rustOut, targets.rust],
    [tsOut, targets.ts],
  ]) {
    try {
      // cwd: a neutral directory. Inside a container or partial checkout the
      // repo's .git may be a dangling worktree pointer, and git fatals on it
      // before honoring --no-index; absolute paths make cwd irrelevant.
      execFileSync('git', ['diff', '--no-index', '--quiet', '--', committed, fresh], {
        stdio: 'ignore',
        cwd: tmpdir(),
      });
    } catch (e) {
      // git exits 1 for "files differ"; anything else is an environment
      // failure that must not masquerade as drift.
      if (e.status !== 1) throw e;
      drift.push(committed);
      // Show what actually differs (the gate's most common failure mode is a
      // platform or toolchain difference, and the diff is the diagnosis).
      try {
        execFileSync('git', ['diff', '--no-index', '--stat', '--', committed, fresh], {
          stdio: 'inherit',
          cwd: tmpdir(),
        });
      } catch {
        /* git diff exits 1 on difference; output already shown */
      }
      try {
        const full = execFileSync('git', ['diff', '--no-index', '--', committed, fresh], {
          encoding: 'utf8',
          maxBuffer: 64 * 1024 * 1024,
          cwd: tmpdir(),
        });
        console.error(full.split('\n').slice(0, 80).join('\n'));
      } catch (e) {
        console.error(String(e.stdout ?? '').split('\n').slice(0, 80).join('\n'));
      }
    }
  }

  if (drift.length > 0) {
    console.error('');
    console.error('Committed Plato clash-math outputs are stale:');
    for (const f of drift) console.error(`     ${f}`);
    console.error('');
    console.error('   Regenerate and commit them:');
    console.error('     node scripts/generate-plato-clash.mjs');
    process.exit(1);
  }
  log('committed Plato clash-math outputs match the .plato source');
}

function main() {
  const check = process.argv.includes('--check');
  const dll = buildCli();
  if (check) {
    checkMode(dll);
  } else {
    generate(dll, { rust: rustOut, ts: tsOut });
    log('done');
  }
}

main();
